(function () {
  const workerSrc = "/static/pdfjs/pdf.worker.min.mjs";

  window.pdfjsLibReady = import("/static/pdfjs/pdf.min.mjs").then((pdfjsLib) => {
    window.pdfjsLib = pdfjsLib;
    if (pdfjsLib.GlobalWorkerOptions) {
      pdfjsLib.GlobalWorkerOptions.workerSrc = workerSrc;
    }
    return pdfjsLib;
  });
})();
